class Solution:
    def getSmallestString(self, s: str) -> str:
        # Convert the string to a list for easy manipulation
        s_list = list(s)
        n = len(s_list)

        # Iterate through the string to find a pair of adjacent digits with the same parity
        for i in range(n - 1):
            # Check if current and next digit have the same parity
            if (int(s_list[i]) % 2 == int(s_list[i + 1]) % 2):
                # Swap them if it leads to a lexicographically smaller string
                if s_list[i] > s_list[i + 1]:
                    s_list[i], s_list[i + 1] = s_list[i + 1], s_list[i]
                    break  # Only one swap allowed

        return ''.join(s_list)
